mapper.select:
SELECT
    id, line_no, deploy_type, deploy_no as no, field, name, status_code, deploy_desc, create_at
FROM deploy


        line_no = #{param.lineNo}


        AND deploy_type = #{param.deployType}


        AND deploy_no = #{param.no}


        AND name like CONCAT(#{param.name}, '%')


        AND field = #{param.field}


LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM deploy


        line_no = #{param.lineNo}


        AND deploy_type = #{param.deployType}


        AND deploy_no = #{param.no}


        AND name like CONCAT(#{param.name}, '%')


        AND field = #{param.field}

SELECT IF(MAX(version) IS NULL, 0, MAX(version))
FROM deploy
WHERE line_no = #{lineNo} AND deploy_no = #{no}
